form:Form.form:Scripts:
		function load()
{              
	//Valida Fecha Desde 
	if(Ctrl('f_desde').GetXValue() == '')
	{
		alert('La Fecha Desde es requerida');
		return false;
	}        
	//Valida Fecha Hasta
	if(Ctrl('f_hasta').GetXValue() == '')
	{
		alert('La Fecha Hasta es requerida');
		return false;
	}        
	//Valida Empresa
	if(Ctrl('empreq').GetEnabled() && Ctrl('empresa').GetXValue() == '')
	{
		alert('La Empresa es requerida');
		return false;
	}
	NomadTimeout("internal_load();",100,"Cargando la Lista..."); 
}

function loadadd() 
{ 
	//Valida Fecha Desde 
	if(Ctrl('f_desde').GetXValue() == '')
	{
		alert('La Fecha Desde es requerida');
		return false;
	}        
	//Valida Fecha Hasta
	if(Ctrl('f_hasta').GetXValue() == '')
	{
		alert('La Fecha Hasta es requerida');
		return false;
	}        
	//Valida Empresa
	if(Ctrl('empreq').GetEnabled() && Ctrl('empresa').GetXValue() == '')
	{
		alert('La Empresa es requerida');
		return false;
	}
	NomadTimeout("internal_loadadd();",100,"Agregando en la Lista..."); 
}
